# tests/prompt_evals/test_customer_triage.py
import anthropic, pytest, json
from pathlib import Path

client = anthropic.Anthropic()

# Load the prompt file being changed in this PR
PROMPT_PATH = Path('prompts/customer-triage.md')
GOLDEN_DATASET_PATH = Path('tests/prompt_evals/datasets/customer-triage.json')

@pytest.fixture(scope='session')
def prompt_text():
    return PROMPT_PATH.read_text()

@pytest.fixture(scope='session')
def golden_dataset():
    return json.loads(GOLDEN_DATASET_PATH.read_text())

@pytest.mark.parametrize('case', json.loads(GOLDEN_DATASET_PATH.read_text()))
def test_triage_classification(case, prompt_text):
    """Each case: {input: str, expected_label: str}"""
    response = client.messages.create(
        model='claude-haiku-4-5',
        max_tokens=50,
        messages=[{'role': 'user', 'content': prompt_text + '\n\n' + case['input']}]
    )
    actual = response.content[0].text.strip().lower()
    assert case['expected_label'].lower() in actual, \
        f"Expected {case['expected_label']}, got: {actual}"

import hashlib
from dataclasses import dataclass
from typing import Optional

@dataclass
class PromptExperiment:
    experiment_id: str
    control_version: str    # version_id for A (baseline)
    treatment_version: str  # version_id for B (new variant)
    treatment_percentage: float  # 0.0 - 1.0, traffic share for B
    metric_name: str        # What to optimize (e.g., 'user_satisfaction')
    active: bool = True

class ABTestRouter:
    def __init__(self, registry: PromptRegistry):
        self.registry = registry
        self.experiments: dict[str, PromptExperiment] = {}
        self.metrics: dict[str, list[dict]] = {}

    def create_experiment(self, prompt_name: str, experiment: PromptExperiment):
        self.experiments[prompt_name] = experiment

    def get_version(self, prompt_name: str, user_id: str) -> PromptVersion:
        """Deterministically assign a user to control or treatment."""
        experiment = self.experiments.get(prompt_name)
        if not experiment or not experiment.active:
            return self.registry.load(prompt_name, 'production')

        # Hash (experiment_id, user_id) for stable assignment
        assignment_key = f"{experiment.experiment_id}:{user_id}"
        hash_val = int(hashlib.md5(assignment_key.encode()).hexdigest(), 16)
        bucket = (hash_val % 1000) / 1000.0

        version_id = (
            experiment.treatment_version
            if bucket < experiment.treatment_percentage
            else experiment.control_version
        )

        # Load by specific version_id
        return self.registry.load_by_id(prompt_name, version_id)

    def record_metric(self, prompt_name: str, user_id: str,
                      metric_value: float):
        """Record outcome for later statistical analysis."""
        experiment = self.experiments.get(prompt_name)
        if not experiment:
            return
        assignment_key = f"{experiment.experiment_id}:{user_id}"
        hash_val = int(hashlib.md5(assignment_key.encode()).hexdigest(), 16)
        variant = 'treatment' if (hash_val % 1000) / 1000.0 < experiment.treatment_percentage else 'control'

        if prompt_name not in self.metrics:
            self.metrics[prompt_name] = []
        self.metrics[prompt_name].append({
            'user_id': user_id,
            'variant': variant,
            'metric': metric_value
        })

    def analyze_experiment(self, prompt_name: str) -> dict:
        """Compute per-variant mean and basic statistical comparison."""
        records = self.metrics.get(prompt_name, [])
        control_vals = [r['metric'] for r in records if r['variant'] == 'control']
        treatment_vals = [r['metric'] for r in records if r['variant'] == 'treatment']

        if not control_vals or not treatment_vals:
            return {'status': 'insufficient_data'}

        control_mean = sum(control_vals) / len(control_vals)
        treatment_mean = sum(treatment_vals) / len(treatment_vals)
        lift = (treatment_mean - control_mean) / control_mean if control_mean else 0

        return {
            'control_mean': control_mean,
            'treatment_mean': treatment_mean,
            'lift': lift,
            'control_n': len(control_vals),
            'treatment_n': len(treatment_vals)
        }
